void accessPage(Cache *cache, int page) {
  int position = findPage(cache->pages, cache->size, page);

  if (position >= 0) {
    moveToMRU(cache->pages, position);
    printHit(page);
    return;
  }

  if (cache->size == CAPACITY) {
    int victim = cache->pages[cache->size - 1];
    removeLRU(cache->pages);
    printEviction(victim);
  }

  insertAtMRU(cache->pages, page);
  printMiss(page);
}
